import clsx from 'clsx'
import type { ReactNode } from 'react'

import type { Tier } from '../data/sandbox'

/* Lightweight ports of dao-frontend primitives (Metric, cards, badges) — presentational only. */

export const Card = ({ children, className }: { children: ReactNode; className?: string }) => (
  <div className={clsx('bg-bg-80 rounded-sm p-6', className)}>{children}</div>
)

export const CardHeader = ({ title, hint }: { title: string; hint?: string }) => (
  <div className="flex items-center justify-between mb-5">
    <span className="font-sora text-sm font-medium text-text-80">{title}</span>
    {hint && (
      <span className="text-[10px] uppercase tracking-widest text-text-40 border border-bg-60 rounded-full px-2 py-0.5">
        {hint}
      </span>
    )}
  </div>
)

export const Metric = ({
  title,
  children,
  footer,
  footerClassName,
}: {
  title: string
  children: ReactNode
  footer?: ReactNode
  footerClassName?: string
}) => (
  <Card className="flex flex-col gap-2">
    <span className="text-sm text-text-40">{title}</span>
    <span className="font-sora text-[2rem] leading-tight font-light text-text-100">{children}</span>
    {footer && <span className={clsx('text-xs', footerClassName ?? 'text-text-40')}>{footer}</span>}
  </Card>
)

export const BucketBadge = ({ tier, className }: { tier: Tier; className?: string }) => (
  <span
    className={clsx(
      'inline-flex items-center gap-2 rounded-full px-3 py-1 text-xs font-medium border',
      className,
    )}
    style={{ color: tier.color, borderColor: tier.color }}
  >
    <span className="w-1.5 h-1.5 rounded-full" style={{ background: tier.color }} />
    Bucket {tier.id} · {tier.name}
  </span>
)

